// Parse Gemini response and extract errors
const item = $input.first().json;

let rawText = "";

// Extract text from various possible structures
if (item.content?.parts?.[0]?.text) {
  rawText = item.content.parts[0].text;
} else if (item.candidates?.[0]?.content?.parts?.[0]?.text) {
  rawText = item.candidates[0].content.parts[0].text;
} else if (typeof item === 'string') {
  rawText = item;
} else {
  rawText = JSON.stringify(item);
}

// Clean markdown fences
rawText = rawText.replace(/```json|```/g, '').trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  console.error('Parse error:', e.message);
  return [{
    json: {
      error: 'Failed to parse Gemini output',
      raw_preview: rawText.substring(0, 500)
    }
  }];
}

const errors = parsed.errors_detected || [];
const summary = parsed.summary || {};
const metadata = parsed.image_metadata || {};

return [{
  json: {
    parsed_response: parsed,
    errors: errors,
    summary: summary,
    metadata: metadata,
    total_errors: errors.length
  }
}];

const item = $input.first();
const base64Image = item.json.base64Image;

// Send FULL image 3 times with focus instructions
const regions = [
  {
    json: {
      base64Image: base64Image,
      mimeType: item.json.mimeType,
      fileName: item.json.fileName,
      region: 'section_1',
      focusArea: 'top_third'
    }
  },
  {
    json: {
      base64Image: base64Image,
      mimeType: item.json.mimeType,
      fileName: item.json.fileName,
      region: 'section_2',
      focusArea: 'middle_third'
    }
  },
  {
    json: {
      base64Image: base64Image,
      mimeType: item.json.mimeType,
      fileName: item.json.fileName,
      region: 'section_3',
      focusArea: 'bottom_third'
    }
  }
];

return regions;

// Try to get execution ID from the Generate Execution ID node
let executionId;

try {
  executionId = $('Generate Execution ID').first().json.executionId;
} catch (e) {
  // Fallback: generate one here if the node didn't execute
  const crypto = require('crypto');
  executionId = crypto.randomUUID();
  console.log('Generated fallback execution ID:', executionId);
}

const crypto = require('crypto');
const inputItem = $input.first().json;
const errors = inputItem.errors || [];

// If no errors, return empty array
if (errors.length === 0) {
  return [];
}

// Split each error into a separate item with its own error_id
return errors.map((error, index) => ({
  json: {
    executionId: executionId,
    error_id: crypto.randomUUID(), // Unique ID for each error
    error_type: error.error_type || 'unknown',
    found_text: error.original_text || '',
    correction: error.corrected_text || '',
    panel_zone: error.location || '',
    issue_description: error.explanation || '',
    confidence: error.severity === 'high' ? '0.9' : error.severity === 'medium' ? '0.7' : '0.5',
    coordinates: error.coordinates || null,
    bbox: error.bbox || null,
    severity: error.severity || 'medium'
  }
}));

const item = $input.first();
const binaryPropertyName = Object.keys(item.binary)[0] || 'data';
const binaryData = item.binary[binaryPropertyName];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
const base64String = buffer.toString('base64');

return [{
  json: {
    base64Image: base64String,
    mimeType: binaryData.mimeType || 'image/jpeg',
    fileName: binaryData.fileName || 'image.jpg'
  },
  binary: {
    data: binaryData  // ← Explicitly named as 'data' to match api4.ai's input field name
  }
}];

const items = $input.all();

let extractedText = [];

items.forEach(item => {
  // Access api4.ai response directly
  if (item.json && item.json.results && Array.isArray(item.json.results)) {
    item.json.results.forEach(result => {
      if (result.entities && Array.isArray(result.entities)) {
        result.entities.forEach(entity => {
          if (entity.kind === 'text' && entity.text) {
            extractedText.push(entity.text);
          }
        });
      }
    });
  }
});

return [{
  json: {
    combinedOCR: {
      fullText: extractedText.join('\n\n'),
      blocks: [],
      totalBlocks: 1
    }
  }
}];
